module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  cluster_enabled_log_types = ["api", "audit"]
  cluster_encryption_config = [{
    resources = ["secrets"]
    provider  = { key_arn = var.kms_key_arn }
  }]
  ...
}

// Pseudo-routing
if (task === 'sentiment') callModel('sentiment-micro');
else if (task === 'transcribe') callModel('asr-micro');

// Data labeling workflow
for (record of domainData) {
  label = getExpertLabel(record);
  saveLabeledData(record, label);
}
